#!/usr/bin/env node
/**
 * build-copilot-prompts.mjs
 *
 * Generates VS Code Copilot prompt files (`prompts/<slug>.prompt.md`) from the
 * canonical skills under `skills/<slug>/SKILL.md`.
 *
 * Single source of truth is `skills/`. Do not edit files under `prompts/` by hand —
 * they are regenerated by this script. Run after editing any SKILL.md.
 *
 * Usage:
 *   node scripts/build-copilot-prompts.mjs
 *   node scripts/build-copilot-prompts.mjs --check   # exit 1 if any file is out of date
 */

import { readdir, readFile, writeFile, mkdir, stat } from "node:fs/promises";
import { existsSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..");
const skillsDir = path.join(repoRoot, "skills");
const promptsDir = path.join(repoRoot, "prompts");

const checkMode = process.argv.includes("--check");

const GENERATED_BANNER =
  "<!-- GENERATED FILE — do not edit by hand. Source: skills/<name>/SKILL.md. Regenerate with: node scripts/build-copilot-prompts.mjs -->";

/**
 * Parse a SKILL.md file. Returns { frontmatter: { name, description }, body }.
 * Frontmatter is a tiny subset of YAML: `key: value` per line, between `---` fences.
 */
function parseSkill(content) {
  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
  if (!match) {
    throw new Error("SKILL.md is missing YAML frontmatter (--- ... ---).");
  }
  const [, fmRaw, body] = match;
  const frontmatter = {};
  for (const line of fmRaw.split("\n")) {
    const m = line.match(/^([A-Za-z0-9_-]+):\s*(.*)$/);
    if (m) frontmatter[m[1]] = m[2].trim();
  }
  if (!frontmatter.name) throw new Error("SKILL.md frontmatter is missing `name`.");
  if (!frontmatter.description)
    throw new Error("SKILL.md frontmatter is missing `description`.");
  return { frontmatter, body: body.trimStart() };
}

/**
 * Build the Copilot `.prompt.md` content from a parsed skill.
 * Copilot prompt files use `mode`, `description`, and the body becomes the prompt content.
 */
function renderPrompt({ frontmatter, body }) {
  const description = frontmatter.description.replace(/"/g, '\\"');
  return [
    "---",
    "mode: agent",
    `description: "${description}"`,
    "---",
    GENERATED_BANNER,
    "",
    `# ${frontmatter.name}`,
    "",
    body.trimEnd(),
    "",
  ].join("\n");
}

async function listSkills() {
  const entries = await readdir(skillsDir, { withFileTypes: true });
  const skills = [];
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const skillPath = path.join(skillsDir, entry.name, "SKILL.md");
    if (!existsSync(skillPath)) continue;
    skills.push({ slug: entry.name, file: skillPath });
  }
  return skills.sort((a, b) => a.slug.localeCompare(b.slug));
}

async function main() {
  if (!existsSync(promptsDir)) {
    await mkdir(promptsDir, { recursive: true });
  }

  const skills = await listSkills();
  if (skills.length === 0) {
    console.error("No skills found under skills/.");
    process.exit(1);
  }

  let drift = false;
  const written = [];

  for (const { slug, file } of skills) {
    const raw = await readFile(file, "utf8");
    let parsed;
    try {
      parsed = parseSkill(raw);
    } catch (err) {
      console.error(`[${slug}] ${err.message}`);
      process.exit(1);
    }

    const outPath = path.join(promptsDir, `${slug}.prompt.md`);
    const next = renderPrompt(parsed);

    if (checkMode) {
      const prev = existsSync(outPath) ? await readFile(outPath, "utf8") : "";
      if (prev !== next) {
        console.error(`[drift] ${path.relative(repoRoot, outPath)} is out of date.`);
        drift = true;
      }
      continue;
    }

    await writeFile(outPath, next, "utf8");
    written.push(path.relative(repoRoot, outPath));
  }

  if (checkMode) {
    if (drift) {
      console.error(
        "\nRun: node scripts/build-copilot-prompts.mjs\nThen commit the regenerated prompts/."
      );
      process.exit(1);
    }
    console.log("prompts/ is up to date.");
    return;
  }

  console.log(`Wrote ${written.length} prompt file(s):`);
  for (const f of written) console.log(`  - ${f}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
